class Solution {
    public int[] gardenNoAdj(int n, int[][] paths) {
        int[] adj = new int[n];
        for (int[] path : paths) {
            adj[path[0] - 1] |= 1 << (path[1] - 1);
            adj[path[1] - 1] |= 1 << (path[0] - 1);
        }
        int[] answer = new int[n];
        for (int i = 0; i < n; i++) {
            int flower = 1;
            while ((adj[i] & (1 << (flower - 1))) != 0) {
                flower++;
            }
            answer[i] = flower;
        }
        return answer;
    }
}
